import{_ as o,o as a,c as i,a3 as t}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Changelog | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/changelog/"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Changelog | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/changelog/"}]]},"headers":[],"relativePath":"changelog/index.md","filePath":"changelog/index.md","lastUpdated":1784163688000}'),n={name:"changelog/index.md"};function l(r,e,s,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="branding-disk-split-local-logos-favicons-2026-07-16" tabindex="-1">Branding disk split (local logos/favicons) (2026-07-16) <a class="header-anchor" href="#branding-disk-split-local-logos-favicons-2026-07-16" aria-label="Permalink to &quot;Branding disk split (local logos/favicons) (2026-07-16)&quot;">​</a></h2><p>Logo and favicon can use a dedicated disk while other uploads stay on S3.</p><ul><li>Env: <code>FILESYSTEM_BRANDING_DISK</code> (defaults to uploads / <code>FILESYSTEM_DISK</code>)</li><li>Production split: <code>FILESYSTEM_DISK=s3</code> + <code>FILESYSTEM_BRANDING_DISK=public</code> + <code>php artisan storage:link</code></li><li><code>FileUploadService</code> branding helpers; central/tenant branding + workspace logos use the branding disk</li><li>Docs: <code>developer-guide/object-storage.md</code>; settings production checklists updated</li></ul><hr><h2 id="lead-import-reusable-import-framework-2026-07-16" tabindex="-1">Lead Import (reusable Import framework) (2026-07-16) <a class="header-anchor" href="#lead-import-reusable-import-framework-2026-07-16" aria-label="Permalink to &quot;Lead Import (reusable Import framework) (2026-07-16)&quot;">​</a></h2><p>Bulk CSV/XLSX lead import with a reusable framework for future modules.</p><ul><li>Permission: <code>leads.import</code> (admin/manager; mirrors export)</li><li>Package: Maatwebsite Laravel Excel; queue: <code>ProcessLeadImportJob</code> on <code>imports</code></li><li>API: template, upload, mapping, options, preview, run, history, original/failed/error downloads</li><li>SPA: 5-step wizard + import history beside Export; polls queued progress</li><li>Duplicate modes: skip / update (needs <code>leads.update</code>) / keep; unique fields email and/or phone</li><li>Single migration <code>lead_imports</code>; row failures as downloadable CSVs (no per-row tables)</li><li>Writes via <code>LeadService::create()</code> / <code>update()</code>; audit <code>lead_import_completed</code> / <code>lead_import_failed</code></li><li>Tests: <code>LeadImportTest</code>; Playwright <code>leads.import.spec.ts</code></li><li>Docs: user/developer/API/deployment guides updated (import no longer deferred)</li></ul><hr><h2 id="tenant-manual-member-email-verification-2026-07-16" tabindex="-1">Tenant manual member email verification (2026-07-16) <a class="header-anchor" href="#tenant-manual-member-email-verification-2026-07-16" aria-label="Permalink to &quot;Tenant manual member email verification (2026-07-16)&quot;">​</a></h2><p>Workspace owners and admins can help members who never receive the verification email.</p><ul><li>Permission: <code>users.verify</code> (owner + admin role map)</li><li>API: <code>POST /api/tenant/v1/users/{user}/verify-email</code>, <code>POST /api/tenant/v1/users/{user}/resend-verification</code></li><li>SPA Users row menu: <strong>Resend verification</strong> / <strong>Mark as verified</strong></li><li>Audit: <code>tenant_user_email_verified</code>, <code>tenant_user_verification_resent</code></li><li>Tests: <code>TenantUserVerifyEmailTest</code>; Playwright tenant RBAC covers mark-as-verified</li></ul><hr><h2 id="dedicated-emails-queue-2026-07-15" tabindex="-1">Dedicated emails queue (2026-07-15) <a class="header-anchor" href="#dedicated-emails-queue-2026-07-15" aria-label="Permalink to &quot;Dedicated emails queue (2026-07-15)&quot;">​</a></h2><p>All <code>ShouldQueue</code> notifications dispatch to the named <code>emails</code> queue via <code>QueuesOnEmails</code>.</p><ul><li>Worker: <code>php artisan queue:work --queue=emails --sleep=1 --tries=3 --max-time=3600</code></li><li>Optional standby: <code>--queue=default</code> for future non-mail jobs</li><li>Docs: production runbook, module-development-developer, backend README Queue Setup</li></ul><hr><h2 id="spa-runtime-config-multi-client-forge-2026-07-15" tabindex="-1">SPA runtime config (multi-client / Forge) (2026-07-15) <a class="header-anchor" href="#spa-runtime-config-multi-client-forge-2026-07-15" aria-label="Permalink to &quot;SPA runtime config (multi-client / Forge) (2026-07-15)&quot;">​</a></h2><p>Frontend API origin is runtime via Forge-generated <code>/config.js</code> (<code>window.env</code>), not baked into CI.</p><ul><li>Deploy script sources site <code>.env</code> and writes <code>VITE_API_URL</code> / <code>VITE_APP_NAME</code> / <code>VITE_API_MODE</code></li><li>Same <code>build-artifacts</code> artifact for every client; each Forge site owns its <code>.env</code></li><li>No committed <code>config.js</code> / <code>config.example.js</code> in the SPA repo</li><li>Docs: <code>architecture/frontend-build-artifacts.md</code>, production runbook</li></ul><hr><h2 id="frontend-production-ci-cd-build-artifacts-2026-07-15" tabindex="-1">Frontend production CI/CD (build-artifacts) (2026-07-15) <a class="header-anchor" href="#frontend-production-ci-cd-build-artifacts-2026-07-15" aria-label="Permalink to &quot;Frontend production CI/CD (build-artifacts) (2026-07-15)&quot;">​</a></h2><p>Automated SPA production builds on merge to <code>main</code> without committing <code>dist/</code> to source.</p><ul><li>GitHub Actions workflow <code>frontend-build.yml</code>: lint, typecheck, Vite production build, validation, secret scan</li><li>Uploads GitHub Actions artifact <code>frontend-build</code> (30-day retention)</li><li>Publishes deployment-ready assets to the <code>build-artifacts</code> branch with <code>build-info.json</code> provenance</li><li>Docs: <code>architecture/frontend-build-artifacts.md</code>; production runbook SPA section updated</li></ul><hr><h2 id="object-storage-migration-wasabi-s3-2026-07-15" tabindex="-1">Object storage migration (Wasabi / S3) (2026-07-15) <a class="header-anchor" href="#object-storage-migration-wasabi-s3-2026-07-15" aria-label="Permalink to &quot;Object storage migration (Wasabi / S3) (2026-07-15)&quot;">​</a></h2><p>All user uploads go through Laravel Storage via <code>FileUploadService</code>. Production uses <code>FILESYSTEM_DISK=s3</code> (Wasabi or any S3-compatible provider); local uses <code>FILESYSTEM_DISK=public</code>.</p><ul><li><code>league/flysystem-aws-s3-v3</code> + full <code>AWS_*</code> env (<code>ENDPOINT</code> / <code>URL</code> for Wasabi)</li><li>Central/tenant branding and admin tenant logos use <code>FileUploadService</code> (unique filenames, relative keys, disk-agnostic URLs)</li><li>Tenancy filesystem bootstrapper no longer remaps the shared <code>public</code>/uploads disk (prefix isolation via <code>tenants/{uuid}/…</code>)</li><li>Artisan <code>storage:migrate-to-s3</code> copies existing local objects idempotently</li><li>Docs: <code>architecture/object-storage.md</code>; settings production guides updated</li></ul><hr><h2 id="go-live-hardening-2026-07-15" tabindex="-1">Go-live hardening (2026-07-15) <a class="header-anchor" href="#go-live-hardening-2026-07-15" aria-label="Permalink to &quot;Go-live hardening (2026-07-15)&quot;">​</a></h2><p>Production readiness audit for Central + Tenant with Leads &amp; Tasks. Billing and security fixes only — no architecture redesign.</p><p><strong>Critical / High</strong></p><ul><li>Module cancel now calls Stripe/Creem <code>cancelSubscription</code> before local entitlement revoke (prevents silent continued charging)</li><li>Failed webhook logs are reclaimed on provider retry (no permanent swallow after a transient 500)</li><li>Recurring <code>invoice.payment_succeeded</code> creates a renewal invoice/payment when the provider transaction id is new</li><li>Cashier <code>/stripe/webhook</code> handles <code>invoice.payment_failed</code></li><li>Email verification asserts the user belongs to the current tenant</li><li>Boot refuses <code>APP_DEBUG=true</code> in production; HTTPS scheme forced in production; <code>SecureHeaders</code> + <code>TrustProxies</code></li><li>Lead CSV export escapes formula injection (<code>=+-@</code>)</li><li>Checkout merges admin <code>gateway_metadata</code> into Stripe/Creem session metadata</li><li>SPA: Leads/Tasks assignee fetches gated on <code>users.list</code> (no spurious 403 toast for staff); assignee fields PermissionGated in create/edit dialogs</li></ul><p><strong>Ops / docs</strong></p><ul><li>CRM due-notification command applies tenant SMTP runtime config</li><li>Production runbook: cache isolation wording, Creem webhook secret, frontend SPA deploy notes</li><li>Tests: cancel-at-gateway, failed-webhook retry, renewal ledger; marketplace Stripe mocks allow <code>completedCheckoutEvent</code></li></ul><hr><h2 id="creem-payment-gateway-2026-07-14" tabindex="-1">Creem payment gateway (2026-07-14) <a class="header-anchor" href="#creem-payment-gateway-2026-07-14" aria-label="Permalink to &quot;Creem payment gateway (2026-07-14)&quot;">​</a></h2><p>Add Creem as a second provider behind the existing <code>PaymentGatewayInterface</code> / <code>GatewayManager</code> stack. Stripe behavior is unchanged.</p><ul><li><code>CreemGateway</code> + HTTP <code>CreemClient</code>, webhook HMAC verification, provider-neutral <code>tenant_gateway_customers</code></li><li>Config: <code>config/creem.php</code> (<code>CREEM_*</code> env fallbacks); seed + admin enable/disable/default/config</li><li>Webhooks: <code>POST /webhooks/gateways/creem</code> (<code>creem-signature</code>) → Billing Engine module activation</li><li>Product mapping uses Creem <code>prod_…</code> ids; Central UI credential fields + Creem-specific mapping copy</li><li>Return-URL / “Complete subscription” sync via <code>confirm-checkout</code> so paid checkouts activate without a second session when webhooks are delayed</li><li>Docs: <code>billing/creem.md</code>; tests: <code>CreemGatewayTest</code>, <code>CreemWebhookTest</code>, <code>CreemCheckoutConfirmTest</code></li></ul><hr><h2 id="provider-agnostic-billing-2026-07-14" tabindex="-1">Provider-agnostic billing (2026-07-14) <a class="header-anchor" href="#provider-agnostic-billing-2026-07-14" aria-label="Permalink to &quot;Provider-agnostic billing (2026-07-14)&quot;">​</a></h2><p>Decouple Modules from Stripe. Stripe is one payment driver; catalog pricing stays on Modules.</p><ul><li>Added <code>payment_gateway_module_prices</code> (gateway × module × billing cycle → product/price references)</li><li>Migrated existing <code>modules.stripe_*</code> IDs into the mapping table, then dropped those columns</li><li>Added <code>modules.currency</code> and <code>workspace_module_subscriptions.payment_gateway_id</code></li><li><code>BillingEngine</code> / <code>StripeGateway</code> resolve checkout prices from mappings; consolidated billing skips recurring-gateway subscriptions</li><li>Central API + UI: Module form is catalog-only; <strong>Payment Gateways → Product Mapping</strong> manages provider refs</li><li>Docs: <code>billing/*</code>, <code>architecture/database.md</code>, <code>api/central-v1.md</code>, <code>admin-ui.md</code></li></ul><hr><h2 id="rc1-—-production-readiness-2026-07-14" tabindex="-1">RC1 — Production Readiness (2026-07-14) <a class="header-anchor" href="#rc1-—-production-readiness-2026-07-14" aria-label="Permalink to &quot;RC1 — Production Readiness (2026-07-14)&quot;">​</a></h2><p>Release Candidate hardening for paying-customer launch. No new business modules. Official notes: <a href="/deployment/rc1-production-readiness">releases/rc1-production-readiness.md</a>. Recommended tag: <code>v1.2.0-rc.1</code>.</p><p><strong>Critical / High</strong></p><ul><li>Revoke Sanctum tokens on user suspend; reject suspended sessions via <code>not.suspended</code></li><li>Webhook unique idempotency + safe payload summaries; Cashier + gateway ingress share claim store</li><li>Registration defaults off; tenant password-reset URLs include <code>workspace</code></li><li>Impersonation limited to workspace owner role</li><li>SPA query-cache cleared on session switches; email-verify URL allowlist; verified gate treats missing timestamp as unverified</li><li>Board APIs cap per-column payload size; drawer query-param history for leads/tasks</li></ul><p><strong>Ops / a11y</strong></p><ul><li>Health check probes Redis when used; skip-to-content; billing ErrorState; remember-me default off</li></ul><hr><h2 id="production-hardening-pass-2026-07-13" tabindex="-1">Production Hardening Pass (2026-07-13) <a class="header-anchor" href="#production-hardening-pass-2026-07-13" aria-label="Permalink to &quot;Production Hardening Pass (2026-07-13)&quot;">​</a></h2><p>Security, ops, and SPA hardening for launch readiness. Platform freeze unchanged (no Features/Plans/Limits reintroduced).</p><p><strong>Critical / High security</strong></p><ul><li>Block assignment of protected <code>superadmin</code> (workspace owner) roles via tenant user APIs</li><li>Central role permission sync filtered to <code>central-api</code> guard only</li><li>Gateway webhooks verify signatures before persisting payloads; store safe summaries only</li><li>Branding uploads reject SVG (stored XSS)</li><li>Narrowed <code>User</code> / <code>CentralUser</code> <code>$fillable</code> privileged fields</li><li>CORS origins pinned via <code>FRONTEND_URL</code> / <code>CORS_ALLOWED_ORIGINS</code> (no <code>*</code>)</li><li>Payment API redacts raw <code>gateway_response</code> / <code>webhook_payload</code></li><li>Webhook + API rate limiting; schedule <code>withoutOverlapping</code></li><li>SPA: safe post-login redirects, route <code>RequireAccess</code> gates, ErrorBoundary, query cache clear on logout</li></ul><p><strong>Ops</strong></p><ul><li>Notifications implement <code>ShouldQueue</code></li><li>Health <code>/up</code> verifies database connectivity</li><li>Production runbook: <a href="/deployment/platform-production-runbook">architecture/platform-production-runbook.md</a></li><li><code>.env.example</code> production guidance</li></ul><hr><h2 id="sprint-2-—-crm-ux-2026-07-13" tabindex="-1">Sprint 2 — CRM UX (2026-07-13) <a class="header-anchor" href="#sprint-2-—-crm-ux-2026-07-13" aria-label="Permalink to &quot;Sprint 2 — CRM UX (2026-07-13)&quot;">​</a></h2><p>Leads/Tasks UX + notifications + tenant dashboard widgets. Platform freeze unchanged.</p><p><strong>Leads</strong></p><ul><li><code>lead_value</code> (renamed from <code>estimated_value</code>); independent status <code>active|waiting|on_hold|closed|archived</code>; priority; assignment history</li><li>Kanban (default) + table; DnD opens drawer, save commits stage; KPIs / board / stats APIs</li><li>Follow-up update/reschedule; export CSV/XLSX (filtered); convert stub (<code>converted_at</code>, activity, status closed — Contacts deferred)</li><li>Permissions: <code>view|create|update|delete|assign|export|convert</code> (no import); assignee scoping without <code>leads.assign</code></li></ul><p><strong>Tasks</strong></p><ul><li><code>waiting</code> status; UI labels <code>open</code> as To Do; board (default) + list; KPIs / board / stats APIs</li><li>Comments + History tabs; <code>tasks.change_due_date</code> required to change <code>due_at</code> after create</li><li>Assignee scoping via <code>tasks.assign</code></li></ul><p><strong>Notifications &amp; dashboard</strong></p><ul><li>Database + mail channels; APIs list / unread-count / mark read / mark all; SPA polls every 25s (Reverb/Echo deferred)</li><li>Hourly <code>crm:send-due-notifications</code> for due/overdue follow-ups and tasks</li><li><code>GET /dashboard</code> widget registry gated by module + permission + assignee scope; no calendar widget until Calendar module</li></ul><p><strong>Docs</strong></p><ul><li>Updated Leads/Tasks guides, database, module-development patterns, tenant UI</li><li>API: <a href="/api/tenant-v1-leads">tenant-v1-leads.md</a>, <a href="/api/tenant-v1-tasks">tenant-v1-tasks.md</a>, <a href="/api/tenant-v1-notifications">tenant-v1-notifications.md</a>, <a href="/api/tenant-v1-dashboard">tenant-v1-dashboard.md</a></li></ul><hr><h2 id="v1-1-0-platform-—-production-ready-2026-07-13" tabindex="-1">v1.1.0-platform — Production Ready (2026-07-13) <a class="header-anchor" href="#v1-1-0-platform-—-production-ready-2026-07-13" aria-label="Permalink to &quot;v1.1.0-platform — Production Ready (2026-07-13)&quot;">​</a></h2><p>Platform foundation declared <strong>Production Ready</strong> and <strong>frozen</strong>. No new business modules in this release — hardening only.</p><p>Official release document: <a href="/changelog/v1.1.0-platform">releases/v1.1.0-platform.md</a><br> Git tag: <code>v1.1.0-platform</code></p><p><strong>Verification</strong></p><ul><li>Pest: <strong>230/230</strong> pass</li><li>Playwright: <strong>69/69</strong> pass (<code>--workers=1</code>, all projects: setup, auth, tenant, chromium)</li><li>Manual Cursor browser happy path: Central + Tenant</li></ul><p><strong>Authentication &amp; SPA</strong></p><ul><li>Auth matrix expanded: Pest + Playwright coverage for lockout messages (includes minutes remaining), remember-me, email verification, registration validation, tenant login, and wrong-workspace rejection</li><li><code>VerifyEmailGate</code> <strong>Sign out</strong> navigates to the context login page after logout</li></ul><p><strong>Billing &amp; gateways</strong></p><ul><li><code>BillingEngine::resolveTenant</code> falls back to <code>payment_id</code> in event metadata when customer/subscription maps are absent</li><li>Gateway webhook failure/cancel Pest coverage</li></ul><p><strong>Validation &amp; settings</strong></p><ul><li>Central user and module validation Pest; Lead validation; module deactivate gate after uninstall</li><li>System settings runtime asserts: Sanctum expiration, locale, Cashier currency, date/time formats</li></ul><p><strong>E2E stability</strong></p><ul><li>Focused auth/tenant/central specs; page-object delete/clone assertions; local Playwright <code>workers: 1</code></li></ul><hr><h2 id="product-roadmap-documented-2026-07-12" tabindex="-1">Product roadmap documented (2026-07-12) <a class="header-anchor" href="#product-roadmap-documented-2026-07-12" aria-label="Permalink to &quot;Product roadmap documented (2026-07-12)&quot;">​</a></h2><ul><li>Added <a href="/getting-started/product-roadmap">product-roadmap.md</a>: CRM → Sales → Billing → Purchasing → Inventory → Finance → HR → future expansion</li><li>Linked from README and platform-freeze docs</li><li>Phase 1 CRM: Leads + Tasks complete; Contacts / Companies / Calendar / Activities next</li></ul><hr><h2 id="tasks-module-2026-07-12" tabindex="-1">Tasks module (2026-07-12) <a class="header-anchor" href="#tasks-module-2026-07-12" aria-label="Permalink to &quot;Tasks module (2026-07-12)&quot;">​</a></h2><p><strong>Architecture</strong></p><ul><li>Second product module; mirrors Leads (flat Laravel, <code>module:tasks</code> + Spatie RBAC)</li><li>Functional differences only: status/priority/complete vs stages/follow-ups</li></ul><p><strong>Backend</strong></p><ul><li>Tables: <code>tasks</code>, <code>task_notes</code>, <code>task_activities</code></li><li><code>TaskService</code>, events/subscriber (audit + assignment mail), tenant API routes</li><li>Permissions: <code>tasks.view|create|update|delete|assign|complete</code></li><li>Pest: <code>tests/Feature/Tenant/Task/TaskTest.php</code></li></ul><p><strong>Frontend</strong></p><ul><li>Tasks list / form dialog / detail drawer; nav gated by module + permission</li><li>Playwright: <code>npm run test:e2e:tasks</code> (<code>--project=tenant</code>)</li></ul><p><strong>Docs</strong></p><ul><li><a href="/user-guide/tasks-overview">modules/tasks.md</a> (+ user / developer / production)</li><li><a href="/api/tenant-v1-tasks">api/tenant-v1-tasks.md</a></li></ul><hr><h2 id="leads-reference-module-2026-07-12" tabindex="-1">Leads reference module (2026-07-12) <a class="header-anchor" href="#leads-reference-module-2026-07-12" aria-label="Permalink to &quot;Leads reference module (2026-07-12)&quot;">​</a></h2><p><strong>Architecture</strong></p><ul><li>First product module on the frozen foundation; blueprint for Tasks and later modules</li><li>Flat Laravel layout (no Modules package); <code>module:leads</code> + Spatie RBAC</li><li>Pipeline-ready domain: stages, status workflow, assignment, notes, follow-ups, timeline</li></ul><p><strong>Backend</strong></p><ul><li>Tables: <code>lead_stages</code>, <code>leads</code>, <code>lead_notes</code>, <code>lead_follow_ups</code>, <code>lead_activities</code></li><li><code>LeadService</code>, events/subscriber (audit + mail notifications), tenant API routes</li><li>Permissions: <code>leads.view|create|update|delete|assign</code></li><li>Auth payload includes <code>modules[]</code> for SPA entitlement gating</li><li>Pest: <code>tests/Feature/Tenant/Lead/LeadTest.php</code></li></ul><p><strong>Frontend</strong></p><ul><li>Leads list / form dialog / detail drawer; nav gated by module + permission</li><li>Playwright: <code>npm run test:e2e:leads</code> (<code>--project=tenant</code>)</li></ul><p><strong>Docs</strong></p><ul><li><a href="/user-guide/leads-overview">modules/leads.md</a> (+ user / developer / production)</li><li><a href="/api/tenant-v1-leads">api/tenant-v1-leads.md</a></li></ul><hr><h2 id="platform-freeze-module-development-standard-2026-07-12" tabindex="-1">Platform Freeze &amp; Module Development Standard (2026-07-12) <a class="header-anchor" href="#platform-freeze-module-development-standard-2026-07-12" aria-label="Permalink to &quot;Platform Freeze &amp; Module Development Standard (2026-07-12)&quot;">​</a></h2><p><strong>Architecture</strong></p><ul><li>Platform foundation locked — no redesign of Auth, Tenancy, RBAC, Billing, Marketplace, Settings, or Gateway architecture except critical security / data-integrity / production bugs</li><li>Official <a href="/developer-guide/module-development">Module Development Standard</a>: flat Laravel layout, catalog + <code>module:</code> + Spatie permissions, audit + activity logging, Pest + Playwright, docs DoD</li><li>Cursor rules added in Backend and Frontend (<code>.cursor/rules/platform-freeze.mdc</code>, <code>module-development.mdc</code>)</li><li><strong>Leads</strong> designated as the reference business module; future modules must mirror it</li></ul><p><strong>Docs</strong></p><ul><li><a href="/getting-started/platform-freeze">architecture/platform-freeze.md</a></li><li><a href="/developer-guide/module-development">modules/module-development.md</a> (+ developer / production)</li></ul><hr><h2 id="production-hardening-2026-07-12" tabindex="-1">Production Hardening (2026-07-12) <a class="header-anchor" href="#production-hardening-2026-07-12" aria-label="Permalink to &quot;Production Hardening (2026-07-12)&quot;">​</a></h2><p><strong>Authentication</strong></p><ul><li>Shared tenant <code>/login</code> with Workspace field (slug/domain); <code>/central/login</code> isolated for platform admins</li><li>Server-owned workspace resolution: host → bearer token → <code>workspace</code> input; fail-closed without context</li><li>Email verification enforced for Central and Tenant (<code>verified</code> middleware + SPA verify pages)</li><li>Sanctum token TTL wired to <code>session_lifetime_minutes</code>; Remember Me extends TTL; login lockout after failed attempts</li><li>Removed client tenant persistence (<code>tenantStorage</code> / <code>VITE_DEFAULT_TENANT_DOMAIN</code>)</li></ul><p><strong>Provisioning &amp; tenancy</strong></p><ul><li>Central workspace create always requires an Owner; settings defaults and default role permissions seeded</li><li>Suspended/archived workspaces denied at the API edge</li></ul><p><strong>Security, payments, impersonation, audit</strong></p><ul><li>Tenant setting cache keys namespaced; isolation Pest coverage</li><li>Stripe webhook signature verification + idempotency; payment matching by metadata; PaymentAttempt logging</li><li>Impersonation issues real tenant tokens with timeout, banner, and revoke-on-end</li><li>Broader PlatformAuditService coverage (auth, workspace, users, roles, settings, modules)</li></ul><p><strong>Client / docs</strong></p><ul><li>Currency, date/time, locale, and timezone formatters consume bootstrap settings; SPA idle logout</li><li>Authentication / tenancy docs updated for hybrid resolution and custom-domain readiness</li></ul><hr><h2 id="manual-qa-—-production-readiness-fixes-2026-07-12" tabindex="-1">Manual QA — Production Readiness Fixes (2026-07-12) <a class="header-anchor" href="#manual-qa-—-production-readiness-fixes-2026-07-12" aria-label="Permalink to &quot;Manual QA — Production Readiness Fixes (2026-07-12)&quot;">​</a></h2><p><strong>Backend</strong></p><ul><li><code>DomainRule</code> now accepts platform hostnames including <code>tenant.localhost</code> and <code>tenant.myapp.com</code> (previously required three labels and rejected local domains)</li><li>Central <code>RoleService</code> lists only <code>central-api</code> roles (orphaned <code>tenant-api</code> rows no longer leak into Central Users/Roles UI)</li><li>Central role create always sets <code>guard_name=central-api</code> and scopes uniqueness to that guard</li><li><code>InitializeTenancy</code> re-resolves and switches tenant per request when the domain/header changes</li><li>New <code>tenant.user</code> middleware rejects Sanctum tokens used against a different workspace (<code>EnsureTenantUserBelongsToCurrentTenant</code>)</li><li>Pest: <code>DomainRuleTest</code>, <code>RoleListIsolationTest</code>, <code>TenantTokenIsolationTest</code></li></ul><p><strong>Frontend</strong></p><ul><li>Tenant form shows domain validation errors and uses <code>tenant.localhost</code> placeholder</li><li>Timezone options always include <code>UTC</code> so the default value displays correctly</li></ul><hr><h2 id="tenant-users-roles-permissions-rbac" tabindex="-1">Tenant Users, Roles &amp; Permissions (RBAC) <a class="header-anchor" href="#tenant-users-roles-permissions-rbac" aria-label="Permalink to &quot;Tenant Users, Roles &amp; Permissions (RBAC)&quot;">​</a></h2><p><strong>Backend</strong></p><ul><li>Per-workspace roles via <code>roles.tenant_id</code> (no Spatie teams); permissions remain shared <code>tenant-api</code> vocabulary</li><li>Expanded <code>config/tenant-permissions.php</code> (users, roles, settings, leads, tasks)</li><li>Tenant User + Role APIs: CRUD, suspend, password change, clone, permissions matrix</li><li>Owner (<code>superadmin</code>) bootstrap with full permissions; protected default roles</li><li>Legacy backfill: <code>php artisan tenants:isolate-roles</code> (+ lazy ensure on Users/Roles APIs)</li><li>Pest: user/role CRUD, permission assignment, authorization, workspace isolation, legacy backfill</li></ul><p><strong>Frontend</strong></p><ul><li>Tenant <code>/users</code>, <code>/roles</code>, <code>/roles/matrix</code> reusing Central pages with workspace-aware copy and routes</li><li>Administration nav: Users / Roles (permission-gated)</li><li>Playwright: <code>npm run test:e2e:tenant-rbac</code></li></ul><p><strong>Docs</strong></p><ul><li><code>authorization/tenant-rbac*.md</code> — architecture, user guide, production security</li></ul><hr><h2 id="tenant-branding-configuration" tabindex="-1">Tenant Branding &amp; Configuration <a class="header-anchor" href="#tenant-branding-configuration" aria-label="Permalink to &quot;Tenant Branding &amp; Configuration&quot;">​</a></h2><p><strong>Backend</strong></p><ul><li><code>TenantSettingService</code> resolves workspace settings with hierarchy: tenant override → tenant profile → Central → system default</li><li>Tenant Settings API: list/update, branding upload, test mail, public bootstrap</li><li>SMTP passwords encrypted; runtime mail uses tenant SMTP when <code>mail_host</code> is set, otherwise Central</li><li>Branding assets stored under <code>tenants/{uuid}/branding/…</code></li><li>Permissions: <code>settings.list</code>, <code>settings.update</code></li><li>Pest coverage for resolver + API</li></ul><p><strong>Frontend</strong></p><ul><li>Tenant Settings page (<code>/settings</code>) — General, Branding, Mail with searchable selects, color picker, uploads</li><li>Settings store bootstraps resolved tenant branding when a workspace domain is known</li><li>Playwright: <code>npm run test:e2e:tenant-settings</code></li></ul><p><strong>Docs</strong></p><ul><li><code>settings/tenant-settings*.md</code> — hierarchy, SMTP, storage, security</li></ul><hr><h2 id="tenant-application-ui-foundation" tabindex="-1">Tenant Application UI Foundation <a class="header-anchor" href="#tenant-application-ui-foundation" aria-label="Permalink to &quot;Tenant Application UI Foundation&quot;">​</a></h2><p><strong>Frontend</strong></p><ul><li>Tenant protected routes now use the shared <code>AppLayout</code> shell (Sidebar, Topbar, Breadcrumbs, Command Palette, User Menu)</li><li>Context-aware navigation: <code>centralNavigationGroups</code> vs <code>tenantNavigationGroups</code></li><li>Tenant sidebar: Dashboard, Leads, Tasks, Settings, Profile</li><li>Tenant dashboard redesigned as layout-matched placeholders (welcome, workspace info, modules, activity, quick actions)</li><li>Leads / Tasks / Tenant Settings reserved via <code>PlaceholderPage</code></li><li>Shared Profile page works on both <code>/profile</code> and <code>/central/profile</code></li></ul><p><strong>Docs</strong></p><ul><li>Shared layout developer + tenant user guides</li><li>Architecture note for shared design system / layout reuse</li></ul><hr><h2 id="tenant-authentication-foundation" tabindex="-1">Tenant Authentication Foundation <a class="header-anchor" href="#tenant-authentication-foundation" aria-label="Permalink to &quot;Tenant Authentication Foundation&quot;">​</a></h2><p><strong>Backend</strong></p><ul><li>Self-service registration creates workspace owner, default roles/permissions, and returns a tenant Sanctum token</li><li>Password reset emails point at SPA routes via <code>FRONTEND_URL</code></li><li>Tenant dashboard placeholder returns workspace + installed modules</li><li>Email verification architecture prepared (<code>MustVerifyEmail</code> + signed verify/resend routes)</li><li>Impersonation helper reserved for future tenant token handoff</li></ul><p><strong>Frontend</strong></p><ul><li>Tenant auth at <code>/login</code>, <code>/register</code>, <code>/forgot-password</code>, <code>/reset-password/{token}</code></li><li>Central auth moved under <code>/central/*</code> with isolated token storage</li><li>Tenant dashboard placeholder for auth/impersonation verification</li></ul><p><strong>Docs / tests</strong></p><ul><li>Authentication developer, user, and production guides</li><li>Pest coverage for tenant auth; Playwright auth suites updated for <code>/central</code> + tenant flows</li></ul><hr><h2 id="features-layer-removed-—-module-licensing-spatie-authorization" tabindex="-1">Features layer removed — module licensing + Spatie authorization <a class="header-anchor" href="#features-layer-removed-—-module-licensing-spatie-authorization" aria-label="Permalink to &quot;Features layer removed — module licensing + Spatie authorization&quot;">​</a></h2><p>Licensing and authorization are fully decoupled.</p><p><strong>Architecture</strong></p><ul><li>Removed Features catalog (model, API, UI, entitlements <code>features[]</code>, <code>features.*</code> permissions, <code>features</code> table)</li><li>Modules remain pure licensing products via <code>workspace_module_subscriptions</code></li><li>User access stays on Spatie Roles &amp; Permissions</li><li>Tenant gating: <code>module:{slug}</code> (licensing) then <code>can:{permission}</code> (authorization)</li><li>Entitlements payload is now <code>{ core, modules }</code> only</li><li>Default modules unchanged: Leads + Tasks (free, included, non-removable)</li></ul><p><strong>Backend</strong></p><ul><li><code>EnsureModule</code> middleware replaces <code>EnsureModuleFeature</code></li><li>Catalog seeder no longer creates Feature rows</li><li>Migration drops <code>features</code> table</li></ul><p><strong>Frontend</strong></p><ul><li>Features admin page, nav, API client, and Playwright suite removed</li><li>Marketplace / tenant details no longer show feature badges</li></ul><hr><h2 id="payment-gateway-management" tabindex="-1">Payment Gateway Management <a class="header-anchor" href="#payment-gateway-management" aria-label="Permalink to &quot;Payment Gateway Management&quot;">​</a></h2><p>Gateway-agnostic payment provider management for Central Billing.</p><p><strong>Architecture</strong></p><ul><li>Billing Engine talks only to <code>PaymentGatewayInterface</code> via <code>GatewayManager</code></li><li>Stripe/Cashier isolated inside <code>StripeGateway</code>; arch tests enforce isolation</li><li>Admin APIs for enable/disable/default/config/mode/test/webhooks/logs/capabilities</li><li>Encrypted gateway credentials; secrets never returned to the frontend</li><li>Generic webhook ingress <code>POST /webhooks/gateways/{code}</code> + Cashier Stripe route</li></ul><p><strong>Schema</strong></p><ul><li>Expanded <code>payment_gateways</code> (mode, encrypted config, webhook/test metadata)</li><li>Added <code>payment_attempts</code>, <code>gateway_logs</code>, <code>webhook_logs</code></li><li><code>payment_methods</code> remains the workspace preferred-method store</li></ul><p><strong>Frontend</strong></p><ul><li>Top-level <strong>Billing</strong> nav: Dashboard, Invoices, Payments, Transactions, Refunds, Payment Methods, Payment Gateways, Coupons, Taxes, Billing Logs</li><li>Full Payment Gateways management UI (configure Stripe fields, sandbox/live, test connection, logs)</li></ul><p><strong>Docs</strong></p><ul><li><code>billing/payment-gateways.md</code> (+ developer/user/production/webhooks guides)</li><li>Updated <code>billing-engine.md</code> and <code>stripe-cashier.md</code></li></ul><hr><h2 id="central-application-settings-refactor" tabindex="-1">Central Application Settings refactor <a class="header-anchor" href="#central-application-settings-refactor" aria-label="Permalink to &quot;Central Application Settings refactor&quot;">​</a></h2><p>Rebuilt system settings so every key is validated and consumed at runtime.</p><p><strong>Backend</strong></p><ul><li>Expanded mail/security/branding/localization settings; removed unused placeholders (<code>primary_color</code>, feature-flag duplicates, display-only queue/disk keys)</li><li>Runtime config overlay (app name, timezone, locale, session lifetime, mail From/SMTP, Cashier currency)</li><li>Encrypted <code>mail_password</code>, branding file uploads, test-mail endpoint</li><li>Public bootstrap + self-service workspace registration gated by <code>registration_enabled</code></li><li>Tenant-only maintenance middleware (<code>tenant.available</code>); Central stays fully operational</li><li>Centralized <code>PasswordRule</code> / <code>Password::defaults()</code> from security settings</li><li>Support email + company name injected into tenant-facing auth emails</li></ul><p><strong>Frontend</strong></p><ul><li>Settings UI rebuilt with SearchableSelect for timezone/locale/currency/formats</li><li>App title, sidebar, button color CSS vars, favicon/logo from public settings</li><li>App-wide date/time helpers; registration-closed and branded maintenance pages</li></ul><p><strong>Tests / docs</strong></p><ul><li>Expanded Pest settings suite; Playwright settings coverage for registration-closed + maintenance copy</li><li>Added Settings user / developer / production guides under <code>settings/</code></li><li>Updated API, admin UI, database, and testing docs</li></ul><hr><h2 id="tenant-form-cleanup" tabindex="-1">Tenant form cleanup <a class="header-anchor" href="#tenant-form-cleanup" aria-label="Permalink to &quot;Tenant form cleanup&quot;">​</a></h2><p>Removed <code>owner_id</code> and <code>address</code> from the <code>tenants</code> schema and admin UI. Timezone, currency, country, and locale are searchable selects. Logo is an image upload (<code>logo</code> file field → <code>logo_path</code> / <code>logo_url</code>).</p><hr><h2 id="central-qa-stabilization-playwright" tabindex="-1">Central QA stabilization (Playwright) <a class="header-anchor" href="#central-qa-stabilization-playwright" aria-label="Permalink to &quot;Central QA stabilization (Playwright)&quot;">​</a></h2><p>Stabilized the Central Application with a full Playwright pass before further Tenant Application work.</p><p><strong>Fixed</strong></p><ul><li>Logout now revokes only the current Sanctum token (was deleting all tokens and breaking parallel E2E sessions)</li><li>Dashboard growth/revenue series API keys aligned to frontend contract (<code>count</code>, <code>amount</code>) — removed chart <code>NaN</code> display</li><li>Settings E2E opens the Billing tab before toggling trial flags</li><li>Auth greeting assertion matches time-based welcome copy</li><li>Roles cleanup searches before deleting the original role after clone</li></ul><p><strong>Added (Playwright)</strong></p><ul><li>Module suites: marketplace, billing, impersonation, permissions, profile</li><li>Per-module npm scripts (<code>test:e2e:marketplace</code>, <code>test:e2e:billing</code>, …)</li><li>Smoke coverage for Marketplace route</li></ul><p><strong>Docs</strong></p><ul><li>Updated <code>testing/playwright.md</code> and Frontend <code>docs/testing/PLAYWRIGHT.md</code></li></ul><hr><h2 id="modular-foundation-complete-phases-1–6" tabindex="-1">Modular foundation complete (Phases 1–6) <a class="header-anchor" href="#modular-foundation-complete-phases-1–6" aria-label="Permalink to &quot;Modular foundation complete (Phases 1–6)&quot;">​</a></h2><p>Delivered marketplace APIs, Billing Engine, impersonation, and the financial ledger on top of the module-licensing foundation.</p><p><strong>Added</strong></p><ul><li>Marketplace: <code>GET /marketplace/modules</code>, <code>GET /marketplace/modules/{module}</code> (published catalog, dependency hints, <code>?tenant_id=</code> install state)</li><li>Module subscriptions: <code>GET /module-subscriptions</code>, show, <code>POST …/cancel</code>, <code>POST …/deactivate</code>; <code>POST /tenants/{tenant}/modules</code> (install)</li><li>Billing Engine (<code>BillingEngine</code>, <code>GatewayManager</code>, <code>ManualGateway</code>, <code>StripeGateway</code>, <code>ProrationCalculator</code>)</li><li>Consolidated billing: <code>php artisan billing:run-consolidated</code> (scheduled daily); one invoice per workspace billing cycle for all billable active modules</li><li>Financial ledger tables + read APIs: <code>invoices</code>, <code>invoice_items</code>, <code>payments</code>, <code>payment_transactions</code>, <code>payment_gateways</code>, <code>payment_methods</code>, <code>billing_addresses</code>, <code>taxes</code>, <code>coupons</code>, <code>refunds</code>, <code>credit_notes</code></li><li>Impersonation: <code>impersonation_sessions</code> table; <code>POST /tenants/{tenant}/impersonate</code>, <code>POST /impersonation/{id}/end</code></li><li>Permissions: <code>module-subscriptions.*</code>, <code>invoices.*</code>, <code>payments.*</code>, <code>impersonation.*</code></li></ul><p><strong>Admin UI</strong></p><ul><li>Marketplace browse screen</li><li>Tenant details tabs: Overview | Modules | Billing; impersonate action with reason prompt</li><li>Module catalog form retains marketplace pricing fields</li></ul><p><strong>Unchanged from prior entry</strong></p><ul><li>Plans removed; Leads + Tasks remain default-included, non-billable</li><li><code>workspace_module_subscriptions</code> is licensing SoT; Cashier/Stripe is a gateway driver only</li></ul><hr><h2 id="module-licensing-foundation-plans-removed" tabindex="-1">Module licensing foundation (Plans removed) <a class="header-anchor" href="#module-licensing-foundation-plans-removed" aria-label="Permalink to &quot;Module licensing foundation (Plans removed)&quot;">​</a></h2><p>Replaced plan-based licensing with workspace module subscriptions.</p><p><strong>Removed</strong></p><ul><li>Plans, plan modules/features/limits, limit definitions, usage counters</li><li>Plan-based <code>tenant_subscriptions</code> / <code>subscription_events</code></li><li>Central API/UI for plans, limits, and tenant-subscriptions</li><li><code>default_plan_id</code> system setting</li></ul><p><strong>Added</strong></p><ul><li>Module catalog fields: <code>uuid</code>, pricing, <code>trial_days</code>, <code>version</code>, <code>status</code>, <code>is_default_included</code>, <code>is_billable</code>, Stripe price IDs</li><li><code>module_categories</code>, <code>module_dependencies</code></li><li><code>workspace_module_subscriptions</code> + history</li><li>Workspace billing profile: <code>billing_anchor_day</code>, <code>billing_cycle</code>, <code>proration_mode</code>, <code>next_billing_at</code></li><li><code>EntitlementService</code> + <code>GET /tenants/{tenant}/entitlements</code></li><li><code>config/core-platform.php</code> for always-on platform capabilities</li><li>Catalog seed: <strong>Leads</strong> and <strong>Tasks</strong> only (included, non-billable)</li><li>New workspaces auto-install Leads + Tasks (<code>source=included</code>, not cancellable by owners)</li></ul><hr><h2 id="prior-central-saas-platform-completion" tabindex="-1">Prior: Central SaaS Platform completion <a class="header-anchor" href="#prior-central-saas-platform-completion" aria-label="Permalink to &quot;Prior: Central SaaS Platform completion&quot;">​</a></h2><p>See git history for the earlier plan-based Central Platform delivery notes (tenants, users, roles, Cashier scaffolding, dashboard). That licensing model has been superseded.</p>',217)])])}const g=o(n,[["render",l]]);export{m as __pageData,g as default};
